/**
 * Language Selector Component
 * 
 * Dropdown component for selecting application language. Supports English
 * and French languages. Closes automatically when clicking outside the component.
 * 
 * Uses SSR-safe hooks and DOM utilities.
 */

import React, { useState, useRef } from 'react';
import { useLanguage } from '@/app/providers/LanguageContext.jsx';
import { useClickOutside } from '@/shared/hooks/useClickOutside.js';
import { useWindowSize } from '@/shared/hooks/useWindowSize.js';
import '/styles/index.css';

const languages = [
  { code: 'en', name: 'English', flag: '🇬🇧' },
  { code: 'fr', name: 'Français', flag: '🇫🇷' },
  { code: 'ar', name: 'العربية', flag: '🇸🇦' },
  { code: 'ha', name: 'Hausa', flag: '🇳🇬' },
];

const LanguageSelector = () => {
  const { currentLanguage, changeLanguage } = useLanguage();
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef(null);
  
  // Use SSR-safe hooks
  const { width: windowWidth } = useWindowSize();
  useClickOutside(dropdownRef, () => {
    if (isOpen) {
      setIsOpen(false);
    }
  }, [isOpen]);

  const handleLanguageChange = (langCode) => {
    changeLanguage(langCode);
    setIsOpen(false);
  };

  const currentLang = languages.find(lang => lang.code === currentLanguage) || languages[0];

  const isMobile = windowWidth <= 480;
  const isSmallMobile = windowWidth <= 360;

  return (
    <div style={{ position: 'relative', zIndex: 1001 }} ref={dropdownRef}>
      <button
        type="button"
        onClick={() => setIsOpen(!isOpen)}
        onKeyDown={(e) => {
          // Prevent Enter key from submitting the form when language selector is focused
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            e.stopPropagation();
            setIsOpen(!isOpen);
          }
        }}
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: isSmallMobile ? '4px' : isMobile ? '6px' : '8px',
          padding: isSmallMobile ? '6px 8px' : isMobile ? '6px 10px' : '8px 12px',
          backgroundColor: 'var(--bg-input)',
          border: '2px solid var(--border-secondary)',
          borderRadius: '4px',
          color: 'var(--text-primary)',
          cursor: 'pointer',
          fontSize: isSmallMobile ? '12px' : isMobile ? '13px' : '14px',
          fontWeight: 600,
          transition: 'all var(--transition-base)',
          minWidth: isSmallMobile ? '70px' : isMobile ? '75px' : '80px',
          justifyContent: 'space-between',
          whiteSpace: 'nowrap',
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.borderColor = 'var(--accent)';
          e.currentTarget.style.boxShadow = '0 0 0 3px rgba(37, 99, 235, 0.1), 0 4px 12px rgba(0, 0, 0, 0.08)';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.borderColor = 'var(--border-secondary)';
          e.currentTarget.style.boxShadow = '0 2px 4px rgba(0, 0, 0, 0.04)';
        }}
        title={`Current language: ${currentLang.name}`}
        aria-label="Select language"
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: isSmallMobile ? '4px' : isMobile ? '5px' : '6px' }}>
          <span style={{ fontSize: isSmallMobile ? '14px' : isMobile ? '16px' : '18px' }}>{currentLang.flag}</span>
          <span>{currentLang.code.toUpperCase()}</span>
        </div>
        <span className="material-symbols-outlined" style={{ fontSize: isSmallMobile ? '14px' : isMobile ? '16px' : '18px', transition: 'transform 0.2s', transform: isOpen ? 'rotate(180deg)' : 'rotate(0deg)' }}>
          expand_more
        </span>
      </button>

      {isOpen && (
        <div
          style={{
            position: 'absolute',
            top: '100%',
            right: 0,
            marginTop: isSmallMobile ? '6px' : isMobile ? '7px' : '8px',
            backgroundColor: 'var(--bg-input)',
            border: '2px solid var(--border-secondary)',
            borderRadius: '4px',
            boxShadow: '0 2px 4px rgba(0, 0, 0, 0.04)',
            minWidth: isSmallMobile ? '130px' : isMobile ? '140px' : '150px',
            zIndex: 1002,
            overflow: 'hidden',
            animation: 'dropdownFadeIn 0.2s ease-out'
          }}
        >
          {languages.map((lang) => (
            <button
              key={lang.code}
              onClick={() => handleLanguageChange(lang.code)}
              style={{
                width: '100%',
                padding: isSmallMobile ? '8px 12px' : isMobile ? '9px 14px' : '10px 16px',
                display: 'flex',
                alignItems: 'center',
                gap: isSmallMobile ? '8px' : isMobile ? '9px' : '10px',
                backgroundColor: currentLanguage === lang.code ? 'var(--bg-hover)' : 'var(--bg-input)',
                color: 'var(--text-primary)',
                border: 'none',
                cursor: 'pointer',
                textAlign: 'left',
                fontSize: isSmallMobile ? '12px' : isMobile ? '13px' : '14px',
                transition: 'all var(--transition-base)',
              }}
              onMouseEnter={(e) => {
                if (currentLanguage !== lang.code) {
                  e.currentTarget.style.backgroundColor = 'var(--bg-hover)';
                }
              }}
              onMouseLeave={(e) => {
                if (currentLanguage !== lang.code) {
                  e.currentTarget.style.backgroundColor = 'transparent';
                }
              }}
            >
              <span style={{ fontSize: isSmallMobile ? '14px' : isMobile ? '16px' : '18px' }}>{lang.flag}</span>
              <span style={{ flex: 1 }}>{lang.name}</span>
              {currentLanguage === lang.code && (
                <span className="material-symbols-outlined" style={{ marginLeft: 'auto', fontSize: isSmallMobile ? '14px' : isMobile ? '16px' : '18px', color: 'var(--accent)' }}>
                  check
                </span>
              )}
            </button>
          ))}
        </div>
      )}

      <style>{`
        @keyframes dropdownFadeIn {
          from {
            opacity: 0;
            transform: translateY(-8px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </div>
  );
};

export default LanguageSelector;

