/**
 * useClickOutside Hook
 * 
 * React hook for detecting clicks outside an element.
 * Uses DOM utilities for SSR safety.
 */

import { useEffect, RefObject } from 'react';
import { addDocumentEventListener } from '@/shared/utils/dom/domUtils.js';

/**
 * Hook to detect clicks outside an element
 * 
 * @param {RefObject|HTMLElement} ref - Element ref or DOM element
 * @param {Function} handler - Callback when click outside detected
 * @param {Array} dependencies - Additional dependencies for effect
 */
export const useClickOutside = (ref, handler, dependencies = []) => {
  useEffect(() => {
    const handleClick = (event) => {
      const element = ref?.current || ref;
      
      // Do nothing if clicking ref's element or descendent elements
      if (!element || element.contains(event.target)) {
        return;
      }

      handler(event);
    };

    const cleanup = addDocumentEventListener('mousedown', handleClick);
    
    return cleanup;
  }, [ref, handler, ...dependencies]);
};

export default useClickOutside;

